  "questionProse": [
    "निम्नलिखित कोड का परिणाम क्या होगा?"
  ],
  "explanationProse": [
    "`Promise.allSettled` प्रत्येक प्रमिस के परिणाम का वर्णन करने वाले वस्तुओं के एक ऐरे को लौटाता है। पहला प्रमिस `fulfilled` होता है और मान `'success'` होता है, इसलिए लॉग स्टेटमेंट `fulfilled: success` प्रिंट करेगा।"
  ]
}
